  insert into public.trips (user_id,name,destination,start_date,end_date,arrival_method,location_label,cover_url,theme_id,primary_color,secondary_color) values (target_user,'Paris & Lisboa','Lisboa e Paris' ,'2026-11-19','2026-11-30','Avião','Lisboa e Paris','https://images.unsplash.com/photo-1499856871958-5b9627545d1a?q=80&w=1400&auto=format&fit=crop','classic','#14212b','#b89d63') returning id into trip_id;
