  insert into public.passengers (trip_id,name,gender,age) values (trip_id,'Fernanda','F',10);
  insert into public.trip_days (trip_id,day_number,date,title,summary,photo_url,status) values (trip_id,1,'2026-11-19','Chegada a Lisboa',null,'https://images.unsplash.com/photo-1585208798174-6cedd86e019a?q=80&w=800&auto=format&fit=crop','planned') returning id into day_id;
  insert into public.activities (day_id,period,position,title,description) values (day_id,'morning',0,'Manhã','Momento livre / sem programação definida.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'afternoon',0,'Tarde','Pouso às 12h10. Com desembarque, imigração e traslado, a chegada ao hotel deve acontecer por volta das 14h–15h. Check-in no Hotel Jardim Lisboa. Um passeio pelo bairro e uma parada obrigatória: o Elevador de Santa Justa, a poucos minutos do hotel, para ver o pôr do sol sobre os telhados da Baixa e o Tejo ao fundo. Uma das vistas mais bonitas de Lisboa — e de graça.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'night',0,'Noite','Caminhada pela Baixa iluminada, descendo pela Rua Augusta até o Arco da Rua Augusta e a Praça do Comércio. Depois, jantar informal no Time Out Market Lisboa, no Mercado da Ribeira, com opções diferentes para cada pessoa. Retorno tranquilo ao Hotel Jardim Lisboa.');
  insert into public.trip_days (trip_id,day_number,date,title,summary,photo_url,status) values (trip_id,2,'2026-11-20','Castelo, Au Revoir Lisboa, Boa Noite Paris',null,'https://www.francetourisme.fr/media/marina-noel/croisere-seine-soiree-1.jpg','planned') returning id into day_id;
  insert into public.activities (day_id,period,position,title,description) values (day_id,'morning',0,'Manhã','O Elétrico 28 — o bondinho clássico de Lisboa — sobe pelas ruelas de Alfama e entrega as crianças direto na porta do Castelo de São Jorge. Muralhas medievais, vistas panorâmicas de 360° sobre a cidade e o Tejo, e os famosos pavões que passeiam livremente pelo pátio. As crianças adoram.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'afternoon',0,'Tarde','Check-out, traslado ao aeroporto de Lisboa. Voo Ryanair FR1083 às 19h20 para Paris-Beauvais, chegada às 22h50. Ônibus executivo até o centro de Paris — chegada ao Yooma Urban Lodge por volta da 01h.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'night',0,'Noite','Noite de viagem. Almoço ou lanche em Lisboa antes do voo.');
  insert into public.trip_days (trip_id,day_number,date,title,summary,photo_url,status) values (trip_id,3,'2026-11-21','Torre Eiffel, Arco do Triunfo e o Sena',null,'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRAYABUzOUHY6XrU_kHabZPYjfdraJSVrCfA510WdDSIg&s=10','planned') returning id into day_id;
  insert into public.activities (day_id,period,position,title,description) values (day_id,'morning',0,'Manhã','A manhã começa na esplanada do Trocadéro, a cerca de 20 minutos a pé do Yooma. A foto em família com a Torre Eiffel ao fundo é obrigatória, seguida da subida à Torre Eiffel. A visita ocupa a manhã, com tempo para contemplar a cidade e descer por volta do meio-dia ou início da tarde.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'afternoon',0,'Tarde','Depois do almoço, seguimos a pé da Torre Eiffel até o Arco do Triunfo, cerca de 2,5 km. Visitamos o Arco e descemos pela Champs-Élysées, caminhando apenas o trecho que fizer sentido para a família. Se as crianças estiverem cansadas, usamos o ônibus 92 ou um táxi a partir da região de Franklin D. Roosevelt/George V até o Pont de l''Alma, próximo ao embarque do Bateaux-Mouches.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'night',0,'Noite','Cruzeiro Bateaux-Mouches pelo Sena, com os monumentos iluminados nas margens e a Torre Eiffel cintilando. O ônibus 92 liga a região do Arco à área do Pont de l''Alma em cerca de 10–12 minutos; um táxi também é uma alternativa simples.');
  insert into public.trip_days (trip_id,day_number,date,title,summary,photo_url,status) values (trip_id,4,'2026-11-22','Louvre e Galeries Lafayette',null,'https://media-cdn.tripadvisor.com/media/attractions-splice-spp-674x446/15/71/fe/16.jpg','planned') returning id into day_id;
  insert into public.activities (day_id,period,position,title,description) values (day_id,'morning',0,'Manhã','O Louvre com estratégia — sem tentar ver tudo, porque isso arruína qualquer museu. Cada um escolhe uma obra para encontrar: Gabriel vai atrás da armadura medieval, Manu da Vênus de Milo, Fefê das múmias egípcias. A Pirâmide de Vidro é parada obrigatória para a foto. Do Yooma, cerca de 35 minutos de metrô.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'afternoon',0,'Tarde','Depois do almoço, seguimos para a Galeries Lafayette Haussmann. A cúpula histórica, as lojas de moda, a área infantil, a perfumaria e o terraço panorâmico formam um bloco de compras e arquitetura. A loja funciona aos domingos, normalmente das 11h às 20h.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'night',0,'Noite','Passeio pela região da Ópera Garnier e pelo Boulevard Haussmann, seguido de jantar. Uma noite mais leve depois do Louvre e das compras.');
  insert into public.trip_days (trip_id,day_number,date,title,summary,photo_url,status) values (trip_id,5,'2026-11-23','Grande Galerie, Panteão e Luxemburgo',null,'https://www.parisselectbook.com/wp-content/uploads/2024/06/retouche-photo-word-press-44.jpg','planned') returning id into day_id;
  insert into public.activities (day_id,period,position,title,description) values (day_id,'morning',0,'Manhã','A manhã é dedicada à Grande Galerie de l''Évolution, no Jardin des Plantes. Os animais em escala real, as baleias, girafas e elefantes tornam a visita visual e envolvente para as crianças e os adultos. Do Yooma, cerca de 30 minutos de metrô.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'afternoon',0,'Tarde','Almoço no McDonald''s próximo ao Jardin des Plantes, como pausa descontraída depois da galeria. Em seguida, caminhada até o Panteão, passando pelo Quartier Latin, para conhecer o monumento e sua importância na história da França.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'night',0,'Noite','No fim da tarde, passeio pelo Jardim de Luxemburgo, com seus jardins, esculturas e lago. Depois, jantar na Rue Mouffetard ou no Quartier Latin — uma noite gastronômica e informal, sem repetir os programas dos outros dias.');
  insert into public.trip_days (trip_id,day_number,date,title,summary,photo_url,status) values (trip_id,6,'2026-11-24','Disneyland Paris — Magia, Marvel e o Grand Finale',null,'https://viagem.cnnbrasil.com.br/wp-content/uploads/sites/5/2024/05/Disneyland-Paris-Facebook.jpg?w=849&h=477&crop=0','planned') returning id into day_id;
  insert into public.activities (day_id,period,position,title,description) values (day_id,'morning',0,'Manhã','Manhã no Disney Adventure World: Frozen Ever After, A Celebration in Arendelle, Raiponce Tangled Spin e Ratatouille.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'afternoon',0,'Tarde','Almoço no Bistrot Chez Rémy e tarde no Disneyland Park, com Big Thunder Mountain, Pirates of the Caribbean, Phantom Manor e outras atrações clássicas.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'night',0,'Noite','Jantar no PYM Kitchen, no Marvel Avengers Campus, seguido do retorno ao Disneyland Park para o espetáculo noturno Disney Tales of Magic.');
  insert into public.trip_days (trip_id,day_number,date,title,summary,photo_url,status) values (trip_id,7,'2026-11-25','Miraculous, Emily in Paris e a Ponte Secreta',null,'https://media.istockphoto.com/id/2217447814/photo/palais-royal-garden-paris.jpg?s=612x612&w=0&k=20&c=ul4xH3j3UtDiat11KweqKx7s8IgFTydPvHN7PRWpj6w=','planned') returning id into day_id;
  insert into public.activities (day_id,period,position,title,description) values (day_id,'morning',0,'Manhã','A manhã começa na Place de l''Estrapade — uma das praças mais discretas e mais filmadas de Paris. É aqui que Emily mora na série: o prédio de pedra com a janela de mansarda no último andar, a boulangerie na esquina, as ruas de paralelepípedo sem um turista à vista. No Miraculous, o mesmo bairro aparece como pano de fundo do cotidiano de Marinette. Para Manu e Fefê, vai parecer que a série saltou da tela. Do Yooma, ~30 minutos de metrô.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'afternoon',0,'Tarde','Almoço no Terra Nera, a poucos minutos a pé da Place de l''Estrapade — pizzaria italiana que aparece em destaque no Emily in Paris e virou parada obrigatória para fãs da série. O cardápio é focado em massas e pizzas napolitanas de qualidade; o ambiente, com azulejos e tijolos aparentes, é exatamente o que aparece nas cenas.
  insert into public.activities (day_id,period,position,title,description) values (day_id,'night',0,'Noite','Jantar no Marais, ~30 minutos de metrô — um dos bairros mais charmosos e animados de Paris, com ruas de paralelepípedo, galerias de arte e restaurantes para todos os gostos.');
  insert into public.trip_days (trip_id,day_number,date,title,summary,photo_url,status) values (trip_id,8,'2026-11-26','Parque dos Príncipes — A Noite de Gabriel',null,'https://t4.ftcdn.net/jpg/05/27/29/11/360_F_527291139_lGEcYVfryzGkdUSaoTZ10codVhxrvcD0.jpg','planned') returning id into day_id;
  insert into public.activities (day_id,period,position,title,description) values (day_id,'morning',0,'Manhã','Momento livre / sem programação definida.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'afternoon',0,'Tarde','A tarde é dedicada a Montmartre, um dos bairros mais charmosos e cinematográficos de Paris. Subimos pela região da Place du Tertre, com seus artistas, cafés e ruas de paralelepípedo, até a Basílica de Sacré-Cœur. A cúpula oferece uma vista ampla de Paris e o próprio bairro rende um passeio muito especial para a família.\n\nDepois, retorno ao Yooma para descansar e se preparar para a noite no Parque dos Príncipes.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'night',0,'Noite','É a noite de Gabriel. A quinta-feira pode ser dia de Champions League — pode haver jogo do PSG em casa, o que tornaria esta noite histórica. Caso não haja jogo, o tour oficial de bastidores com acesso ao vestiário e ao gramado é igualmente inesquecível. A loja oficial do clube fica dentro do estádio, com personalização de camisa no local. O Parque dos Príncipes fica a 2,4 km do Yooma — 10 minutos de metrô ou táxi.
  insert into public.trip_days (trip_id,day_number,date,title,summary,photo_url,status) values (trip_id,9,'2026-11-27','A Opulência de Versalhes — e Uma Noite de Luz',null,'https://cdn-imgix.headout.com/media/images/f723e5369a607694d95a9e0c1de3a1a3-7654-1.jpg?auto=compress%2Cformat&w=900&h=562.5&q=90&ar=16%3A10&fit=crop','planned') returning id into day_id;
  insert into public.activities (day_id,period,position,title,description) values (day_id,'morning',0,'Manhã','O Palácio de Versalhes merece um dia inteiro. A manhã é dedicada aos apartamentos reais e à Galeria dos Espelhos — um dos espaços mais fotografáveis do mundo, onde cada detalhe foi construído para impressionar. E impressiona até hoje. O RER C parte da estação Javel, a 600m do Yooma, direto para Versalhes.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'afternoon',0,'Tarde','Os jardins a bordo de um minicarro elétrico privativo. A escala dos jardins de Versalhes é difícil de imaginar antes de estar lá — são quilômetros de alamedas, fontes e geometria perfeita. O carrinho transforma o que seria uma caminhada exaustiva em algo próximo de uma aventura.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'night',0,'Noite','O espetáculo Lumières en Seine no Domaine National de Saint-Cloud: 2km de percurso noturno com 25 instalações de luz e música, fontes dançantes, projeções monumentais e vista direta para a Torre Eiffel ao fundo. Com bebidas quentes e pretzels no frio de novembro.');
  insert into public.trip_days (trip_id,day_number,date,title,summary,photo_url,status) values (trip_id,10,'2026-11-28','Comprinhas e Au Revoir, Paris',null,'https://rtlimages.apple.com/cmc/dieter/store/16_9/R675.png','planned') returning id into day_id;
  insert into public.activities (day_id,period,position,title,description) values (day_id,'morning',0,'Manhã','Uma última volta pela Champs-Élysées: Apple Store, Nike e Adidas flagship — grandes lojas, estoque completo, preços europeus. Le Marais para quem quer algo além do óbvio: sneakers, streetwear, lojas independentes em ruas de paralelepípedo. Ambos a ~35 minutos de metrô do Yooma.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'afternoon',0,'Tarde','Retorno ao Yooma, check-out, e transfer em direção a Beauvais. O voo exige saída de Paris por volta das 17h — lanche rápido antes do transfer. Voo Ryanair FR1084 às 20h20, chegada a Lisboa às 21h55. Check-in no Your Lisbon Home Parque das Nações.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'night',0,'Noite','Momento livre / sem programação definida.');
  insert into public.trip_days (trip_id,day_number,date,title,summary,photo_url,status) values (trip_id,11,'2026-11-29','Sintra e o Atlântico',null,'https://images.unsplash.com/photo-1555881400-74d7acaacd8b?q=80&w=800&auto=format&fit=crop','planned') returning id into day_id;
  insert into public.activities (day_id,period,position,title,description) values (day_id,'morning',0,'Manhã','Trem Lisboa → Sintra (~40–50 min a partir da Gare do Oriente, a 13 minutos a pé do apartamento). Chegada cedo — a vila enche a partir das 11h. O Palácio da Pena, com suas cores e sua posição no alto da serra, é uma das construções mais singulares da Europa. As crianças adoram a escala de castelo de conto de fadas.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'afternoon',0,'Tarde','Almoço em restaurante em Sintra — merecido após a subida. Retorno a Lisboa. Passeio leve pelo Chiado ou Bairro Alto.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'night',0,'Noite','Jantar tranquilo em Lisboa — última noite europeia com calma.');
  insert into public.trip_days (trip_id,day_number,date,title,summary,photo_url,status) values (trip_id,12,'2026-11-30','Oceanário e o Voo de Volta',null,'https://cdn-imgix.headout.com/tour/30792/TOUR-IMAGE/45d95207-7811-4cd8-b467-0f0f8ee97a85-16423-lisbon-lisbon-walking-tour---entry-ticket-to-lisbon-oceanarium-05.jpg','planned') returning id into day_id;
  insert into public.activities (day_id,period,position,title,description) values (day_id,'morning',0,'Manhã','O Oceanário de Lisboa fica a 1,6 km do apartamento — a pé, sem metrô, sem pressa. Um dos maiores e mais bonitos da Europa, com o tanque central de dar silêncio na sala. Lontras, arraias, polvos, tubarões — é o tipo de lugar em que as crianças param de correr. E os adultos também. Saída até ~13h.');
  insert into public.activities (day_id,period,position,title,description) values (day_id,'afternoon',0,'Tarde','Um último café com pastel de nata na orla do Parque das Nações — lanche de despedida. O aeroporto Humberto Delgado fica a 4 km do apartamento, menos de 10 minutos de táxi. Voo LIS 15h50 → LHR → GRU 21h15, chegada a Guarulhos em 1º de dezembro às 06h00.
  insert into public.activities (day_id,period,position,title,description) values (day_id,'night',0,'Noite','Momento livre / sem programação definida.');
